% Cálculo das variáveis y usando a transformação quadrática (diferente de L2ZDT1)
y = zeros(m,1);
for i = 1:m
    y(i) = 0;
    for j = 1:m
        y(i) = y(i) + M(i,j) * x(j)^2; % Note o uso do quadrado aqui
    end
end
% Função objetivo 1
f1 = y(1)^2;
% Função g(x)
gx = 1 + 9/(m-1) * sum(y(2:m).^2);
% Função h
h = 1 - sqrt(f1/gx);
% Vetor de funções objetivo
f = [f1; gx*h];
% Não há restrições de desigualdade para este problema
end

